UPDATE EMP_PAY_INFO
SET END_DTM = TO_DATE(#{endDtm}, 'YYYY-MM-DD')
WHERE PAY_SEQ = #{paySeq}

UPDATE GRADE_BASE_AMT
SET END_DTM = TO_DATE(#{endDtm}, 'YYYY-MM-DD')
WHERE BASE_AMT_NO = #{baseAmtNo}

UPDATE SALARY_ITEM
   SET SALARY_ITEM_NAME = #{salaryItemName},
       ITEM_TYPE        = #{itemType},
       TAX_TYPE         = #{taxType}
 WHERE SALARY_ITEM_CODE = #{salaryItemCode}

UPDATE INSURANCE_RATE
SET END_DTM = TO_DATE(#{endDtm}, 'YYYY-MM-DD')
WHERE RATE_NO = #{rateNo}

mapper.select:
SELECT COUNT(1)
FROM PAYROLL
WHERE EMP_NO = #{empNo}
  AND PAY_YYYYMM = #{payYyyymm}

