UPDATE PAYROLL_ITEM
SET AMOUNT = #{amount}
WHERE ITEM_DETAIL_NO = #{itemDetailNo}

UPDATE PAYROLL
SET CONFIRM_YN = #{confirmYn}
WHERE PAYROLL_NO = #{payrollNo}

UPDATE PAYROLL
SET
  TOTAL_PAY_AMT = #{totalPayAmt},
  TOTAL_DEDUCT_AMT = #{totalDeductAmt},
  NET_PAY_AMT = #{netPayAmt}
WHERE PAYROLL_NO = #{payrollNo}

